final:
module RefModule (  
    input [7:0] feature1,  
    input [7:0] feature2,  
    input [7:0] feature3,  
    output reg prediction  
);  
    wire [15:0] weighted_sum;  
    parameter weight1 = 3;  
    parameter weight2 = 2;  
    parameter weight3 = 5;  
    parameter bias = 10;  
      wire _n01 = (feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[0] ^ bias[0];
  wire _c01 = (feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[0] & bias[0];
  wire _n02 = (feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[1] ^ bias[1] ^ _c01;
  wire _c02 = ((feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[1] & bias[1]) | ((feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[1] & _c01) | (bias[1] & _c01);
  wire _n03 = (feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[2] ^ bias[2] ^ _c02;
  wire _c03 = ((feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[2] & bias[2]) | ((feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[2] & _c02) | (bias[2] & _c02);
  wire _n04 = (feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[3] ^ bias[3] ^ _c03;
  wire _c04 = ((feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[3] & bias[3]) | ((feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[3] & _c03) | (bias[3] & _c03);
  assign weighted_sum = {_n01, _n02, _n03, _n04};  
    always @(*) begin  
        if (weighted_sum >= 50)  
            prediction = 1;  
        else  
            prediction = 0;  
    end  
endmodule
